const fs = require\('fs'\);
const path = require\('path'\);
const dir = path.resolve\('d:/Usersolutons/EDGEBIC Description/EDGEBIC_Web_Description/content/blog'\);
const files = fs.readdirSync\(dir\).filter\(f => f.endsWith\('.mdx'\)\);
console.log\('Total MDX files scanned:', files.length\);
let fixed = 0;
for \(const f of files\) {
  const fp = path.join\(dir, f\);
  let c = fs.readFileSync\(fp, 'utf8'\);
  // Match both absolute \(https://usersolutions.com/contact\) and relative \(/contact\)
  // but NOT /contact-us
  const pattern = /\(\\\(https:\\/\\/usersolutions\\.com\\/contact\\\)|\\\(\\/contact\\\)\)/g;
  if \(pattern.test\(c\)\) {
    // Reset lastIndex since we used .test\(\)
    pattern.lastIndex = 0;
    const count = \(c.match\(pattern\) || []\).length;
    const updated = c.replace\(pattern, \(match\) => {
      if \(match === '\(/contact\)'\) return '\(/contact-us\)';
      return '\(https://usersolutions.com/contact-us\)';
    }\);
    if \(updated !== c\) {
      fs.writeFileSync\(fp, updated\);
      console.log\('Fixed:', f, '\(' + count + ' occurrence\(s\)\)'\);
      fixed++;
    }
  }
}
console.log\('Total files fixed:', fixed\);
ENDSCRIPT)
